// File: MainActivity.kt
// A minimal Activity that: shows a counter, survives rotation, and persists to bundle.
import android.os.Bundle
import android.util.Log
import android.widget.Button
import android.widget.TextView
import androidx.activity.viewModels
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewmodel.initializer
import androidx.lifecycle.viewmodel.viewModelFactory
import androidx.lifecycle.createSavedStateHandle

// 1. ViewModel ŌĆö survives config changes; SavedStateHandle survives process death too
class CounterVM(private val handle: SavedStateHandle) : ViewModel() {
  var count: Int
    get() = handle["count"] ?: 0
    set(value) { handle["count"] = value }

  fun increment() { count += 1 }

  companion object {
    val Factory = viewModelFactory {
      initializer { CounterVM(createSavedStateHandle()) }
    }
  }
}

class MainActivity : AppCompatActivity() {
  private val vm: CounterVM by viewModels { CounterVM.Factory }

  override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)
    Log.d("LIFECYCLE", "onCreate ŌĆö was recreated? ${savedInstanceState != null}")

    val text = TextView(this)
    val button = Button(this).apply { text = "+1" }

    fun render() { text.text = "count = ${vm.count}" }
    render()

    button.setOnClickListener {
      vm.increment()   // survives rotation because it's in a ViewModel
      render()
    }

    // (In a real app you'd inflate a layout instead)
  }

  override fun onStart()   { super.onStart();   Log.d("LIFECYCLE", "onStart") }
  override fun onResume()  { super.onResume();  Log.d("LIFECYCLE", "onResume") }
  override fun onPause()   { super.onPause();   Log.d("LIFECYCLE", "onPause") }
  override fun onStop()    { super.onStop();    Log.d("LIFECYCLE", "onStop") }
  override fun onDestroy() { super.onDestroy(); Log.d("LIFECYCLE", "onDestroy") }
}

